		if (a <= l&&r <= b) {

			lazy[k] = x; push(k); return;

		}

		update(a, b, x, k * 2 + 1, l, (l + r) / 2);

		update(a, b, x, k * 2 + 2, (l + r) / 2, r);

		update_node(k);

	}

	inline T query(int a, int b, int k, int l, int r) {

		push(k);

