	REP(i, h) cin>>a[i];

	bool det = false;

	REP(i, h) {

		REP(j, w) {

			if(a[i][j] == 'S') {

				sp.first = i;

				sp.second = j;

				det = true;

				break;

			}

		}

		if(det) break;

	}

	REP(i, n) {

		queue<P> c;

		c.push(sp);

		dist[sp.first][sp.second] = 0;

		while(true) {

			P cp = c.front();

			c.pop();

			if(a[cp.first][cp.second] - '1' == i) {

				time += dist[cp.first][cp.second];

				sp = cp;

				break;

			}

			REP(j, 4) {

				ll nx = cp.first + dx[j];

				ll ny = cp.second + dy[j];

				if(nx >= 0 && nx < h && ny >= 0 && ny < w && dist[nx][ny] == INF && (a[nx][ny] == 'S' || a[nx][ny] == '.' || (a[nx][ny] >= '1' && a[nx][ny] <= '9'))) {

					c.push(P(nx, ny));

					dist[nx][ny] = dist[cp.first][cp.second] + 1;

				}

			}

		}

		REP(j, h) {

			REP(k, w) {

				dist[j][k] = INF;

			}

		}

	}

	cout<<time<<endl;

}
